pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_MODULATION.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("level_in", "Input Gain", None, Some(1.0), 0.015625, 64.0, 0.1, ParameterUnit::None),
            float_parameter("level_out", "Output Gain", None, Some(1.0), 0.015625, 64.0, 0.1, ParameterUnit::None),
            float_parameter("mode", "Mode", None, Some(0.0), 0.0, 4.0, 0.01, ParameterUnit::None),
            float_parameter("freq", "Frequency", None, Some(1.0), 0.01, 100.0, 0.1, ParameterUnit::Hertz),
            float_parameter("amount", "Modulation", None, Some(1.0), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("offset", "Offset L/R", None, Some(0.5), 0.0, 1.0, 0.01, ParameterUnit::None),
            bool_parameter("mono", "Mono-in", None, Some(false)),
            bool_parameter("reset", "Reset", None, Some(false)),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let level_in = required_f32(params, "level_in").map_err(anyhow::Error::msg)?;
    let level_out = required_f32(params, "level_out").map_err(anyhow::Error::msg)?;
    let mode = required_f32(params, "mode").map_err(anyhow::Error::msg)?;
    let freq = required_f32(params, "freq").map_err(anyhow::Error::msg)?;
    let amount = required_f32(params, "amount").map_err(anyhow::Error::msg)?;
    let offset = required_f32(params, "offset").map_err(anyhow::Error::msg)?;
    let mono = required_bool(params, "mono").map_err(anyhow::Error::msg)?;
    let reset = required_bool(params, "reset").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_LEVEL_IN, level_in),
        (PORT_CTRL_LEVEL_OUT, level_out),
        (PORT_CTRL_MODE, mode),
        (PORT_CTRL_FREQ, freq),
        (PORT_CTRL_AMOUNT, amount),
        (PORT_CTRL_OFFSET, offset),
        (PORT_CTRL_MONO, if mono { 1.0 } else { 0.0 }),
        (PORT_CTRL_RESET, if reset { 1.0 } else { 0.0 }),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN_L, PORT_AUDIO_IN_IN_R], &[PORT_AUDIO_OUT_OUT_L, PORT_AUDIO_OUT_OUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

